def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    P = list(map(int, data[1:N+1]))

    rank = [0] * N
    r = 1
    assigned = [False] * N

    while sum(assigned) < N:
        max_score = -1
        max_indices = []
        for i in range(N):
            if not assigned[i] and P[i] > max_score:
                max_score = P[i]
                max_indices = [i]
            elif not assigned[i] and P[i] == max_score:
                max_indices.append(i)

        for idx in max_indices:
            rank[idx] = r
        r += len(max_indices)
        for idx in max_indices:
            assigned[idx] = True

    for i in range(N):
        print(rank[i])

if __name__ == "__main__":
    main()
